import React, { Component } from 'react'

export class ProcessorBox extends Component {
    render() {
        return (
            <div style={processorBoxContainer}>
                <div style={lineDashed}></div>
                    <div style={processorBoxProgressPipeContainer}>
                        <div style={processorBox}>ProcessorBox</div>
                        <div style={progressPipe}></div>
                    </div>
                <div style={lineDashed}></div>
            </div>
        )
    }
}

export default ProcessorBox

const processorBoxContainer = {
    width: "300px",
}

const processorBox = {
    backgroundColor : "#e3e3e3",
    padding: "30px 0px",
    borderRadius: "0px",
    border: "1px solid black",
    width: "50%"
}

const lineDashed = {
    borderRight: "2px dashed lightgrey",
    width: "95px",
    height: "20px",
}

const processorBoxProgressPipeContainer = {
    display: "grid",
}

const progressPipe = {
    height: "40px", 
    backgroundColor: "white", 
    marginTop: "auto", 
    marginBottom: "auto",
    borderTop: "4px solid #e3e3e3",
    borderBottom: "4px solid #e3e3e3"
}
